html = "<!DOCTYPE html>\n<html>\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n<style>\n:root{\n  --bg:#07080b;\n  --panel:#111620;\n  --cell:#171b23;\n  --cell2:#1b202a;\n  --grid:#424957;\n  --gold:#c8aa63;\n  --text:#e7ebf0;\n  --muted:#98a1ad;\n  --mark:#5f6f58;\n  --mark2:#77876e;\n  --free:#2b3140;\n  --sky:#8eb8d8;\n  --warn:#c89055;\n}\n*{box-sizing:border-box}\nhtml,body{\n  margin:0;\n  min-height:100%;\n  color:var(--text);\n  font-family:Inter,system-ui,\"Segoe UI\",Arial,sans-serif;\n  overflow-x:hidden;\n  background:\n    radial-gradient(circle at 50% -10%, rgba(200,170,99,.11), transparent 24%),\n    linear-gradient(180deg,#090b10 0%,#050609 100%);\n}\n.app{\n  position:relative;\n  z-index:2;\n  width:min(94vw,600px);\n  margin:0 auto;\n  padding:10px 8px 24px;\n}\n\n/* visible Wings-of-Glory-ish air combat background */\n.sky-layer{position:fixed;inset:0;pointer-events:none;z-index:0;overflow:hidden}\n.jet{\n  position:absolute;\n  width:88px;height:34px;\n  opacity:.48;\n  filter:drop-shadow(0 0 10px rgba(142,184,216,.22));\n  animation:jetPatrol 12s ease-in-out infinite alternate;\n}\n.jet svg{width:100%;height:100%;stroke:var(--sky);fill:none;stroke-width:2.2;stroke-linecap:round;stroke-linejoin:round}\n.jet.j1{left:5vw;top:20vh}\n.jet.j2{right:6vw;top:30vh;transform:scaleX(-1);animation-delay:1.2s}\n.jet.j3{left:10vw;bottom:16vh;animation-delay:2.2s}\n@keyframes jetPatrol{\n  from{transform:translate(0,0) rotate(-5deg);opacity:.28}\n  to{transform:translate(34px,-28px) rotate(4deg);opacity:.62}\n}\n.jet.j2{animation-name:jetPatrol2}\n@keyframes jetPatrol2{\n  from{transform:translate(0,0) scaleX(-1) rotate(5deg);opacity:.28}\n  to{transform:translate(-34px,-26px) scaleX(-1) rotate(-4deg);opacity:.62}\n}\n\n.contrail{\n  position:absolute;\n  width:160px;height:2px;\n  background:linear-gradient(90deg,transparent,rgba(142,184,216,.38),rgba(200,170,99,.22),transparent);\n  transform:rotate(-13deg);\n  opacity:.45;\n  animation:trailDrift 6s ease-in-out infinite alternate;\n}\n.ct1{left:10vw;top:26vh}\n.ct2{right:8vw;top:37vh;animation-delay:1.5s}\n.ct3{left:13vw;bottom:22vh;animation-delay:2.4s}\n@keyframes trailDrift{\n  from{transform:translateX(0) rotate(-13deg);opacity:.25}\n  to{transform:translateX(30px) rotate(-13deg);opacity:.60}\n}\n\n.radar{\n  position:absolute;\n  width:96px;height:96px;\n  border:1px solid rgba(142,184,216,.22);\n  border-radius:50%;\n  opacity:.5;\n  animation:radarPulse 3.4s ease-in-out infinite;\n}\n.radar:before,.radar:after{\n  content:\"\";\n  position:absolute;\n  inset:18px;\n  border:1px solid rgba(142,184,216,.18);\n  border-radius:50%;\n}\n.radar:after{inset:36px}\n.r1{right:9vw;bottom:16vh}\n.r2{left:6vw;top:54vh;animation-delay:1.2s}\n@keyframes radarPulse{\n  0%,100%{transform:scale(.95);opacity:.22}\n  50%{transform:scale(1.08);opacity:.55}\n}\n\n.missile{\n  position:absolute;\n  width:70px;height:10px;\n  opacity:.42;\n  animation:missileMove 7s ease-in-out infinite alternate;\n}\n.missile:before{\n  content:\"\";\n  position:absolute;\n  left:0;right:0;top:4px;height:2px;\n  background:linear-gradient(90deg,transparent,rgba(200,170,99,.6));\n}\n.missile:after{\n  content:\"\";\n  position:absolute;\n  right:0;top:1px;\n  border-left:12px solid var(--warn);\n  border-top:4px solid transparent;\n  border-bottom:4px solid transparent;\n}\n.m1{left:7vw;bottom:35vh}\n.m2{right:10vw;top:52vh;transform:scaleX(-1);animation-delay:1.7s}\n@keyframes missileMove{\n  from{transform:translateX(0)}\n  to{transform:translateX(35px)}\n}\n\n/* header */\n.header{text-align:center;margin:4px auto 8px}\n.title-box{\n  display:inline-block;\n  padding:8px 18px 10px;\n  background:rgba(12,16,23,.64);\n  border:1px solid rgba(200,170,99,.18);\n  box-shadow:0 12px 30px rgba(0,0,0,.24);\n}\n.title{\n  color:var(--gold);\n  font-size:clamp(30px,5.2vw,46px);\n  font-weight:900;\n  letter-spacing:-.055em;\n  line-height:.94;\n}\n.title span{display:block;font-size:.64em}\n\n/* toolbar */\n.toolbar{\n  width:max-content;\n  max-width:100%;\n  margin:0 auto 10px;\n  padding:5px;\n  display:flex;\n  gap:5px;\n  align-items:center;\n  background:rgba(15,19,27,.94);\n  border:1px solid rgba(255,255,255,.08);\n}\n.icon-btn{\n  width:34px;height:34px;\n  border:1px solid rgba(200,170,99,.34);\n  background:#111620;\n  color:var(--gold);\n  cursor:pointer;\n  display:grid;\n  place-items:center;\n  transition:transform .12s ease,filter .12s ease,border-color .12s ease;\n}\n.icon-btn svg{width:18px;height:18px;stroke:currentColor;fill:none;stroke-width:2.4;stroke-linecap:round;stroke-linejoin:round}\n.icon-btn:hover{transform:translateY(-1px);filter:brightness(1.12);border-color:var(--gold)}\n.icon-btn:active{transform:scale(.96)}\n.board-select{\n  height:34px;\n  border:1px solid rgba(200,170,99,.34);\n  background:#111620;\n  color:var(--gold);\n  font-weight:800;\n  outline:none;\n  padding:0 7px;\n}\n\n/* more basic board */\n.boards{display:grid;gap:12px;justify-content:center}\n.boards.one{grid-template-columns:minmax(300px,min(74vmin,470px))}\n.boards.two,.boards.three,.boards.four{\n  grid-template-columns:repeat(2,minmax(260px,1fr));\n  width:min(94vw,820px);\n  margin-left:50%;\n  transform:translateX(-50%);\n}\n.boards.five,.boards.six{\n  grid-template-columns:repeat(3,minmax(220px,1fr));\n  width:min(96vw,940px);\n  margin-left:50%;\n  transform:translateX(-50%);\n}\n.board-shell{\n  background:#0f131b;\n  border:2px solid var(--grid);\n  padding:2px;\n  box-shadow:0 0 18px rgba(0,0,0,.35);\n}\n.board{\n  display:grid;\n  grid-template-columns:repeat(5,1fr);\n  gap:1px;\n  background:var(--grid);\n  aspect-ratio:1/1;\n}\n.cell{\n  position:relative;\n  overflow:hidden;\n  border:0;\n  background:var(--cell);\n  color:var(--text);\n  font-size:clamp(9px,1.42vw,13px);\n  line-height:1.08;\n  font-weight:760;\n  text-align:center;\n  padding:5px;\n  cursor:pointer;\n  display:flex;\n  align-items:center;\n  justify-content:center;\n  user-select:none;\n  transition:background .13s ease, filter .13s ease, box-shadow .13s ease;\n}\n.cell:nth-child(even){background:var(--cell2)}\n.boards.two .cell,.boards.three .cell,.boards.four .cell{font-size:clamp(8px,1vw,11px)}\n.boards.five .cell,.boards.six .cell{font-size:clamp(7px,.75vw,9px)}\n.cell:hover{filter:brightness(1.10);box-shadow:inset 0 0 0 1px rgba(200,170,99,.42)}\n.cell.free{\n  background:var(--free)!important;\n  color:var(--gold);\n  font-style:italic;\n  cursor:default;\n  box-shadow:inset 0 0 0 1px rgba(200,170,99,.22);\n}\n.cell.free:hover{filter:none;box-shadow:inset 0 0 0 1px rgba(200,170,99,.22)}\n.cell.marked{\n  background:linear-gradient(180deg,var(--mark2),var(--mark))!important;\n  color:#f4f7f1;\n  box-shadow:inset 0 0 0 1px rgba(230,220,175,.20), inset 0 0 12px rgba(255,255,255,.035);\n  animation:markSet .18s ease;\n}\n.cell.marked::after{\n  content:\"\u2713\";\n  position:absolute;\n  right:5px;\n  bottom:0;\n  font-size:16px;\n  opacity:.32;\n}\n@keyframes markSet{\n  from{filter:brightness(1.35)}\n  to{filter:brightness(1)}\n}\n.cell.rolling:not(.free){animation:softSwap .22s ease}\n@keyframes softSwap{\n  0%{filter:brightness(.75)}\n  60%{filter:brightness(1.18)}\n  100%{filter:brightness(1)}\n}\n\n/* modal */\n.modal-backdrop{\n  position:fixed;inset:0;background:rgba(0,0,0,.68);\n  display:none;align-items:center;justify-content:center;z-index:50;padding:20px;\n}\n.modal-backdrop.show{display:flex}\n.modal{\n  width:min(92vw,390px);\n  background:#101722;\n  border:1px solid rgba(200,170,99,.25);\n  padding:18px;\n  box-shadow:0 0 36px rgba(0,0,0,.55);\n}\n.modal h2{margin:0 0 10px;color:var(--gold);font-size:30px}\n.modal p{margin:8px 0;font-weight:700}\n.close{\n  margin-top:14px;width:100%;height:36px;\n  border:1px solid rgba(200,170,99,.34);\n  background:#111620;color:var(--gold);font-weight:900;cursor:pointer;\n}\n.bingo-modal .modal{text-align:center}\n.bingo-modal h2{\n  font-size:clamp(52px,10vw,86px);\n  animation:jackpot .75s ease-in-out infinite alternate;\n  text-shadow:0 0 16px var(--gold),0 0 32px var(--pink);\n}\n@keyframes jackpot{from{transform:scale(1)}to{transform:scale(1.05);filter:brightness(1.2)}}\n.confetti{\n  position:fixed;top:-20px;font-size:18px;z-index:60;\n  animation:fall 1.25s linear forwards;\n}\n@keyframes fall{to{transform:translateY(110vh) rotate(360deg);opacity:.25}}\n@media(max-width:760px){\n  .boards.two,.boards.three,.boards.four,.boards.five,.boards.six{grid-template-columns:1fr;width:min(94vw,500px)}\n  .cell,.boards.two .cell,.boards.three .cell,.boards.four .cell,.boards.five .cell,.boards.six .cell{font-size:clamp(9px,2.35vw,12px)}\n}\n</style>\n</head>\n<body>\n  <div class=\"sky-layer\">\n    <div class=\"jet j1\"><svg viewBox=\"0 0 70 28\"><path d=\"M4 15h40L65 5l-9 10 9 10-21-10H4z\"></path><path d=\"M25 15 12 6M25 15 12 24\"></path></svg></div>\n    <div class=\"jet j2\"><svg viewBox=\"0 0 70 28\"><path d=\"M4 15h40L65 5l-9 10 9 10-21-10H4z\"></path><path d=\"M25 15 12 6M25 15 12 24\"></path></svg></div>\n    <div class=\"jet j3\"><svg viewBox=\"0 0 70 28\"><path d=\"M4 15h40L65 5l-9 10 9 10-21-10H4z\"></path><path d=\"M25 15 12 6M25 15 12 24\"></path></svg></div>\n    <div class=\"contrail ct1\"></div><div class=\"contrail ct2\"></div><div class=\"contrail ct3\"></div>\n    <div class=\"radar r1\"></div><div class=\"radar r2\"></div>\n    <div class=\"missile m1\"></div><div class=\"missile m2\"></div>\n  </div>\n\n  <div class=\"app\">\n    <div class=\"header\">\n      <div class=\"title-box\">\n        <div class=\"title\">Low Rank<span>Bingo</span></div>\n      </div>\n    </div>\n\n    <div class=\"toolbar\">\n      <button class=\"icon-btn\" title=\"Roll\" onclick=\"rollBoards()\">\n        <svg viewBox=\"0 0 24 24\"><rect x=\"4\" y=\"4\" width=\"16\" height=\"16\"></rect><circle cx=\"8\" cy=\"8\" r=\"1\"></circle><circle cx=\"16\" cy=\"8\" r=\"1\"></circle><circle cx=\"12\" cy=\"12\" r=\"1\"></circle><circle cx=\"8\" cy=\"16\" r=\"1\"></circle><circle cx=\"16\" cy=\"16\" r=\"1\"></circle></svg>\n      </button>\n      <button class=\"icon-btn\" title=\"Reset\" onclick=\"resetMarks()\">\n        <svg viewBox=\"0 0 24 24\"><path d=\"M4 12a8 8 0 1 0 3-6\"></path><path d=\"M4 4v6h6\"></path></svg>\n      </button>\n      <button class=\"icon-btn\" title=\"Rules\" onclick=\"openRules()\">\n        <svg viewBox=\"0 0 24 24\"><path d=\"M9.5 9a2.5 2.5 0 1 1 4.3 1.7c-1.2 1-1.8 1.5-1.8 3.1\"></path><path d=\"M12 18h.01\"></path><circle cx=\"12\" cy=\"12\" r=\"9\"></circle></svg>\n      </button>\n      <select class=\"board-select\" id=\"boardCount\" title=\"Boards\" onchange=\"setBoardCount(this.value)\">\n        <option value=\"1\">1 board</option>\n        <option value=\"2\">2 boards</option>\n        <option value=\"3\">3 boards</option>\n        <option value=\"4\">4 boards</option>\n        <option value=\"5\">5 boards</option>\n        <option value=\"6\">6 boards</option>\n      </select>\n    </div>\n\n    <div id=\"boards\" class=\"boards one\"></div>\n  </div>\n\n  <div id=\"rulesModal\" class=\"modal-backdrop\" onclick=\"closeRules(event)\">\n    <div class=\"modal\">\n      <h2>Rules</h2>\n      <p>\u2022 Click a square when it happens.</p>\n      <p>\u2022 Free space starts marked.</p>\n      <p>\u2022 5 in a row wins.</p>\n      <p>\u2022 Rows, columns, diagonals count.</p>\n      <button class=\"close\" onclick=\"hideRules()\">Close</button>\n    </div>\n  </div>\n\n  <div id=\"bingoModal\" class=\"modal-backdrop bingo-modal\" onclick=\"hideBingo()\">\n    <div class=\"modal\">\n      <h2>BINGO!</h2>\n      <p>jackpot hit</p>\n      <button class=\"close\" onclick=\"hideBingo()\">Close</button>\n    </div>\n  </div>\n\n<script>\nconst ITEMS = [\"\\\"add 5th gen aircrafts!\\\"\", \"DOGSHIT opinion or suggestion\", \"corny ass profile/pfp\", \"\\\"errrmm is all bvr so it's LAME\\\"\", \"chaff = flare\", \"thinks they're good\", \"nerf f14a or phoenix missiles\", \"compares wog to wt\", \"doesn't know any bfm/acm\", \"\\\"codes?\\\"\", \"add their favorite niche aircraft\", \"\\\"i have a life/whats wrong with low rank\\\"\", \"realized they have no image perms\", \"\\\"My rank ingame is higher\\\"\", \"extremely biased\", \"intentional rule breaking\", \"\\\"when update?\\\" bro the update is soon chilllll\", \"bitching about killstealing\", \"\\\"(decent plane) is so bad\\\"\", \"\\\"(premium plane) is p2w...\\\"\", \"\\\"add (insert nation) tree!\\\"\", \"can't lose their argument\", \"rants about russian aircrafts\", \"huge fuckass ego\"];\nlet boards=[]; let marked=[]; let boardCount=1; let rolling=false;\nfunction shuffle(arr){const a=[...arr];for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}\nfunction makeBoard(){const items=shuffle(ITEMS);const board=[];let idx=0;for(let i=0;i<25;i++){if(i===12)board.push(\"FREE SPACE\");else board.push(items[idx++]);}return board;}\nfunction classForCount(){if(boardCount===1)return\"one\";if(boardCount===2)return\"two\";if(boardCount===3)return\"three\";if(boardCount===4)return\"four\";if(boardCount===5)return\"five\";return\"six\";}\nfunction setBoardCount(n){boardCount=Math.max(1,Math.min(6,Number(n)));while(boards.length<boardCount){boards.push(makeBoard());marked.push(new Set([12]));}while(boards.length>boardCount){boards.pop();marked.pop();}render();}\nfunction render(){const root=document.getElementById(\"boards\");root.className=\"boards \"+classForCount();root.innerHTML=\"\";for(let b=0;b<boardCount;b++){const shell=document.createElement(\"div\");shell.className=\"board-shell\";const board=document.createElement(\"div\");board.className=\"board\";for(let i=0;i<25;i++){const cell=document.createElement(\"div\");cell.className=\"cell\";if(i===12)cell.classList.add(\"free\");if(marked[b].has(i))cell.classList.add(\"marked\");cell.textContent=boards[b][i];cell.onclick=()=>toggleCell(b,i);board.appendChild(cell);}shell.appendChild(board);root.appendChild(shell);}}\nfunction toggleCell(b,i){if(i===12||rolling)return;const root=document.getElementById(\"boards\");const boardEl=root.children[b].querySelector(\".board\");const cell=boardEl.children[i];if(marked[b].has(i)){marked[b].delete(i);cell.classList.remove(\"marked\");}else{marked[b].add(i);cell.classList.add(\"marked\");}if(hasBingo(marked[b]))showBingo();}\nfunction winLines(){const lines=[];for(let r=0;r<5;r++)lines.push([0,1,2,3,4].map(c=>r*5+c));for(let c=0;c<5;c++)lines.push([0,1,2,3,4].map(r=>r*5+c));lines.push([0,6,12,18,24]);lines.push([4,8,12,16,20]);return lines;}\nfunction hasBingo(set){return winLines().some(line=>line.every(i=>set.has(i)));}\nfunction rollBoards(){if(rolling)return;rolling=true;const allCells=()=>Array.from(document.querySelectorAll(\".cell:not(.free)\"));let steps=10;function spin(step){const tempBoards=Array.from({length:boardCount},()=>makeBoard());allCells().forEach((cell,idx)=>{const boardIndex=Math.floor(idx/24);const innerIndex=idx%24;const pool=tempBoards[boardIndex].filter((_,i)=>i!==12);cell.textContent=pool[innerIndex]||ITEMS[Math.floor(Math.random()*ITEMS.length)];cell.classList.remove(\"marked\");cell.classList.remove(\"rolling\");void cell.offsetWidth;cell.classList.add(\"rolling\");});if(step<steps){setTimeout(()=>spin(step+1),55+step*10);}else{boards=Array.from({length:boardCount},()=>makeBoard());marked=Array.from({length:boardCount},()=>new Set([12]));rolling=false;render();}}spin(0);}\nfunction resetMarks(){marked=Array.from({length:boardCount},()=>new Set([12]));render();}\nfunction openRules(){document.getElementById(\"rulesModal\").classList.add(\"show\")}function hideRules(){document.getElementById(\"rulesModal\").classList.remove(\"show\")}function closeRules(e){if(e.target.id===\"rulesModal\")hideRules()}function showBingo(){document.getElementById(\"bingoModal\").classList.add(\"show\");confettiBurst()}function hideBingo(){document.getElementById(\"bingoModal\").classList.remove(\"show\")}\nfunction confettiBurst(){const shapes=[\"\u2708\",\"\u2605\",\"\u25c6\",\"\u25cf\",\"B\",\"\u2713\"];const colors=[\"#d8b05c\",\"#d95772\",\"#47e6a0\",\"#61c8e8\",\"#ffffff\"];for(let i=0;i<32;i++){const s=document.createElement(\"div\");s.className=\"confetti\";s.textContent=shapes[Math.floor(Math.random()*shapes.length)];s.style.left=Math.random()*100+\"vw\";s.style.color=colors[Math.floor(Math.random()*colors.length)];s.style.animationDelay=Math.random()*.15+\"s\";document.body.appendChild(s);setTimeout(()=>s.remove(),1500);}}\ndocument.addEventListener(\"keydown\",e=>{if(e.key===\"Escape\"){hideRules();hideBingo();}});\nboards=[makeBoard()];marked=[new Set([12])];render();\n</script>\n</body>\n</html>\n"

components.html(html, height=900, scrolling=True)
